import { Anthropic } from '@anthropic-ai/sdk';

const client = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });

const tools = [
  {
    name: 'detect_intent',
    description: 'Detect email processing intent',
    input_schema: {
      type: 'object',
      properties: {
        email_content: { type: 'string' },
        intent: { type: 'string', enum: ['reply', 'forward', 'archive'] }
      }
    }
  },
  {
    name: 'scan_pii',
    description: 'Scan email for PII before processing',
    input_schema: {
      type: 'object',
      properties: { content: { type: 'string' } }
    }
  }
];

const message = await client.messages.create({
  model: 'claude-3-5-sonnet-20240620',
  max_tokens: 1024,
  tools,
  messages: [{ role: 'user', content: `Analyze: ${emailBody}` }],
  tool_choice: 'auto'
});

const toolResults = await Promise.all(
  message.tool_calls?.map(async (tool) => {
    // Execute tool logic
    return { name: tool.name, result: await executeTool(tool) };
  }) ?? []
);

