const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

// After Claude processes tools
const toolOutputs = message.tool_calls.map(t => t.input);

const verification = await vex.verify({
  inputs: toolOutputs,
  policies: [
    'pii_filtering',
    'tone_appropriateness',
    'recipient_validation',
    'content_accuracy',
    'confidentiality_enforcement'
  ],
  context: {
    senderDomain: 'company.com',
    allowedRecipients: ['@company.com'],
    requiredTone: 'professional',
    maxPII: 0
  }
});

if (!verification.valid) {
  console.error('Vex blocked unsafe email:', verification.issues);
  return { blocked: true, reasons: verification.issues };
}

